CREATE
    OR REPLACE PROCEDURE public.sp_truncate_and_insert_zoominfo_standard()
    LANGUAGE plpgsql AS
$$
BEGIN -- Step 4: https://worth-ai.atlassian.net/browse/INFRA-55
    DROP TABLE IF EXISTS datascience.zoominfo_standard;
    CREATE TABLE datascience.zoominfo_standard DISTKEY(zi_es_location_id)
                                               INTERLEAVED
                                                   SORTKEY
                                                   (
                                                   zi_c_location_id,
                                                   zi_c_company_id,
                                                   zi_es_location_id
                                                   ) AS
    WITH
        country_filter AS (
            SELECT
                zi_c_location_id,
                zi_c_company_id,
                zi_es_location_id,
                CASE UPPER(TRIM(base.zi_c_country))
                    WHEN 'UNITED KINGDOM'
                        THEN REGEXP_SUBSTR(SPLIT_PART(UPPER(zi_c_zip), ' ', 1), '^([A-Z]*)')
                    WHEN 'UNITED STATES'
                        THEN region_code
                    WHEN 'CANADA'
                        THEN region_code
                    WHEN 'IRELAND'
                        THEN
                            CASE WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%CARLOW%' THEN 'CARLOW'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%CAVAN%' THEN 'CAVAN'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%CLARE%' THEN 'CLARE'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%CORK%' THEN 'CORK'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%DONEGAL%' THEN 'DONEGAL'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%DUBLIN%' THEN 'DUBLIN'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%GALWAY%' THEN 'GALWAY'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%KERRY%' THEN 'KERRY'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%KILDARE%' THEN 'KILDARE'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%KILKENNY%' THEN 'KILKENNY'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%LAOIS%' THEN 'LAOIS'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%LEITRIM%' THEN 'LEITRIM'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%LIMERICK%' THEN 'LIMERICK'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%LONGFORD%' THEN 'LONGFORD'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%LOUTH%' THEN 'LOUTH'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%MAYO%' THEN 'MAYO'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%MEATH%' THEN 'MEATH'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%MONAGHAN%' THEN 'MONAGHAN'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%OFFALY%' THEN 'OFFALY'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%ROSCOMMON%' THEN 'ROSCOMMON'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%SLIGO%' THEN 'SLIGO'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%TIPPERARY%' THEN 'TIPPERARY'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%WATERFORD%' THEN 'WATERFORD'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%WESTMEATH%' THEN 'WESTMEATH'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%WEXFORD%' THEN 'WEXFORD'
                            WHEN UPPER(zi_c_city||zi_c_state) ILIKE '%WICKLOW%' THEN 'WICKLOW'
                        ELSE ie."region" END
                    ELSE NULL
                END AS "region",
                CASE UPPER(TRIM(base.zi_c_country))
                    WHEN 'UNITED KINGDOM'
                        THEN 'GB'
                    WHEN 'UNITED STATES'
                        THEN country_code
                    WHEN 'CANADA'
                        THEN country_code
                    WHEN 'IRELAND'
                        THEN 'IE'
                    ELSE NULL
                END AS country
            FROM
                zoominfo.comp_standard_global AS base
                LEFT JOIN datascience.ml_regions AS reg
                    ON reg.country_name_upper = UPPER(base.zi_c_country)
                    AND reg.region_name_upper = UPPER(base.zi_c_state)
                LEFT JOIN datascience.ml_ireland AS ie
                    ON UPPER(LEFT(zi_c_zip, 3)) = ie.postal_code_prefix
            WHERE
                country IS NOT NULL
        ),
        businesses AS (
            SELECT
                zi_c_location_id,
                zi_c_company_id,
                zi_es_location_id,
                "region",
                country
            FROM
                country_filter as base
            INNER JOIN datascience.ml_regions as reg
                ON base.country = reg.country_code
                AND base."region" = reg.region_code
        ),
        names AS (SELECT
                      zi_c_location_id,
                      zi_c_company_id,
                      zi_es_location_id,
                      zi_c_name AS company_name
                  FROM businesses AS busi
                      INNER JOIN zoominfo.comp_standard_global AS base
                              USING (
                                     zi_c_location_id,
                                     zi_c_company_id,
                                     zi_es_location_id
                          )
                  WHERE zi_c_name <> ''
                    AND zi_c_name IS NOT NULL
                  UNION ALL
                  SELECT
                      zi_c_location_id,
                      zi_c_company_id,
                      zi_es_location_id,
                      zi_c_name_display AS company_name
                  FROM businesses AS busi
                      INNER JOIN zoominfo.comp_standard_global AS base
                              USING (
                                     zi_c_location_id,
                                     zi_c_company_id,
                                     zi_es_location_id
                          )
                  WHERE zi_c_name_display <> ''
                    AND zi_c_name_display IS NOT NULL
                --   UNION ALL
                --   SELECT
                --       zi_c_location_id,
                --       zi_c_company_id,
                --       zi_es_location_id,
                --       CAST(name_array[ordinal] AS VARCHAR) AS company_name
                --   FROM (SELECT
                --             base.zi_c_location_id,
                --             base.zi_c_company_id,
                --             base.zi_es_location_id,
                --             split_to_array(base.zi_c_names_other, '|') AS name_array
                --         FROM zoominfo.comp_standard_global AS base
                --             INNER JOIN businesses
                --                     USING (
                --                            zi_c_location_id,
                --                            zi_c_company_id,
                --                            zi_es_location_id
                --                 )
                --         WHERE base.zi_c_names_other <> ''
                --           AND base.zi_c_names_other IS NOT NULL
                --   ) AS base
                --       CROSS JOIN datascience.ml_number1k
                --   WHERE ordinal < get_array_length(name_array)
        ),
        normalized_names AS (SELECT DISTINCT
                                 zi_c_location_id,
                                 zi_c_company_id,
                                 zi_es_location_id,
                                 sanitize_business_name(company_name) AS company_name,
                                 canonize_business_name(company_name) AS normalized_name
                             FROM names
        ),
        normalized_addresses AS (SELECT
                                     zi_c_location_id,
                                     zi_c_company_id,
                                     zi_es_location_id,
                                     country,
                                     zi_c_county,
                                     zi_c_latitude,
                                     zi_c_longitude,
                                     "region",
                                     TRIM(
                                             REPLACE(
                                                     REPLACE(
                                                             REPLACE(
                                                                     REGEXP_REPLACE(
                                                                             TRANSLATE(
                                                                                     UPPER(zi_c_city),
                                                                                     'ÂÁÀÃÄÉÈÊËÍÌÎÏÓÒÕÖÔÚÙÛÜÇ',
                                                                                     'AAAAAEEEEIIIIOOOOOUUUUC'
                                                                             ),
                                                                             '[^A-Z 0-9]',
                                                                             ''
                                                                     ),
                                                                     ' ',
                                                                     '$#'
                                                             ),
                                                             '#$',
                                                             ''
                                                     ),
                                                     '$#',
                                                     ' '
                                             )
                                     )   AS city,
                                     CASE busi.country
                                         WHEN 'US' THEN LPAD(SPLIT_PART(TRIM(zi_c_zip), '-', 1), 5, '0')
                                         WHEN 'CA' THEN REGEXP_REPLACE(UPPER(zi_c_zip), '[^A-Z0-9]')
                                         WHEN 'GB' THEN REGEXP_REPLACE(UPPER(zi_c_zip), '[^A-Z0-9]')
                                         ELSE NULL
                                     END AS zipcode,
                                     LPAD(SPLIT_PART(TRIM(zi_c_zip), '-', 2), 4, '0') AS zi_eng_zip4,
