                                                                                                                                                                                                                                                                                             ),
                                                                                                                                                                                                                                                                                             ' LK ',
                                                                                                                                                                                                                                                                                             ' LAKE '
                                                                                                                                                                                                                                                                                     ),
                                                                                                                                                                                                                                                                                     ' LGT ',
                                                                                                                                                                                                                                                                                     ' LIGHT '
                                                                                                                                                                                                                                                                             ),
                                                                                                                                                                                                                                                                             ' MDWS ',
                                                                                                                                                                                                                                                                             ' MEADOWS '
                                                                                                                                                                                                                                                                     ),
                                                                                                                                                                                                                                                                     ' MNR ',
                                                                                                                                                                                                                                                                     ' MANOR '
                                                                                                                                                                                                                                                             ),
                                                                                                                                                                                                                                                             ' MTN ',
                                                                                                                                                                                                                                                             ' MOUNTAIN '
                                                                                                                                                                                                                                                     ),
                                                                                                                                                                                                                                                     ' MTWY ',
                                                                                                                                                                                                                                                     ' MOTORWAY '
                                                                                                                                                                                                                                             ),
                                                                                                                                                                                                                                             ' PASS ',
                                                                                                                                                                                                                                             ' PASS '
                                                                                                                                                                                                                                     ),
                                                                                                                                                                                                                                     ' PT ',
                                                                                                                                                                                                                                     ' POINT '
                                                                                                                                                                                                                             ),
                                                                                                                                                                                                                             ' RADL ',
                                                                                                                                                                                                                             ' RADIAL '
                                                                                                                                                                                                                     ),
                                                                                                                                                                                                                     ' RCH ',
                                                                                                                                                                                                                     ' REACH '
                                                                                                                                                                                                             ),
                                                                                                                                                                                                             ' RST ',
                                                                                                                                                                                                             ' REST '
                                                                                                                                                                                                     ),
                                                                                                                                                                                                     ' SHRS ',
                                                                                                                                                                                                     ' SHORES '
                                                                                                                                                                                             ),
                                                                                                                                                                                             ' SPG ',
                                                                                                                                                                                             ' SPRING '
                                                                                                                                                                                     ),
                                                                                                                                                                                     ' SQ ',
                                                                                                                                                                                     ' SQUARE '
                                                                                                                                                                             ),
                                                                                                                                                                             ' STA ',
                                                                                                                                                                             ' STATION '
                                                                                                                                                                     ),
                                                                                                                                                                     ' TRCE ',
                                                                                                                                                                     ' TRACE '
                                                                                                                                                             ),
                                                                                                                                                             ' TRL ',
                                                                                                                                                             ' TRAIL '
                                                                                                                                                     ),
                                                                                                                                                     ' TRFY ',
                                                                                                                                                     ' TRAFFICWAY '
                                                                                                                                             ),
                                                                                                                                             ' TUNN ',
                                                                                                                                             ' TUNNEL '
                                                                                                                                     ),
                                                                                                                                     ' VLY ',
                                                                                                                                     ' VALLEY '
                                                                                                                             ),
                                                                                                                             ' VW ',
                                                                                                                             ' VIEW '
                                                                                                                     ),
                                                                                                                     ' XING ',
                                                                                                                     ' CROSSING '
                                                                                                             ),
                                                                                                             ' S ',
                                                                                                             ' SOUTH '
                                                                                                     ),
                                                                                                     ' N ',
                                                                                                     ' NORTH '
                                                                                             ),
                                                                                             ' W ',
                                                                                             ' WEST '
                                                                                     ),
                                                                                     ' E ',
                                                                                     ' EAST '
                                                                             ),
                                                                             ' SE ',
                                                                             ' SOUTHEAST '
                                                                     ),
                                                                     ' NE ',
                                                                     ' NORTHEAST '
                                                             ),
                                                             ' SW ',
                                                             ' SOUTHWEST '
                                                     ),
                                                     ' NW ',
                                                     ' NORTHWEST '
                                             )
                                     )   AS street_address
                                 FROM businesses AS busi
                                     INNER JOIN zoominfo.comp_standard_global AS base
                                             USING (
                                                    zi_c_location_id,
                                                    zi_c_company_id,
                                                    zi_es_location_id
                                         )
                                 WHERE zi_c_street <> ''
                                   AND zi_c_street IS NOT NULL
                                   AND zi_c_zip <> ''
                                   AND zi_c_zip IS NOT NULL
        ),
        other_fields AS (SELECT
                            zi_c_location_id,
                            zi_c_company_id,
                            zi_es_location_id,
                            zi_c_names_other,
                            zi_c_year_founded,
                            zi_c_ein,
                            zi_c_phone,
                            zi_c_fax,
                            zi_c_url,
                            REPLACE(
                                REPLACE(
                                    REPLACE(
                                        UPPER(TRIM(zi_c_url))
                                        , 'WWW.', '')
                                    , 'HTTPS://', '')
                                , 'HTTP://', '')                        AS zi_eng_website,
                            LTRIM(REGEXP_SUBSTR(zi_c_phone, ' [0-9]+')) AS zi_eng_phone_number,
                            REGEXP_SUBSTR(zi_c_phone, '\\+[0-9]+')      AS zi_eng_phone_countrycode,
                            LTRIM(REGEXP_SUBSTR(zi_c_fax, ' [0-9]+'))   AS zi_eng_fax_number,
                            REGEXP_SUBSTR(zi_c_fax, '\\+[0-9]+')        AS zi_eng_fax_countrycode
                         FROM businesses AS busi
                             INNER JOIN zoominfo.comp_standard_global AS base
                                     USING (
                                            zi_c_location_id,
                                            zi_c_company_id,
                                            zi_es_location_id
                                 )
        )
    SELECT DISTINCT
        zi_c_location_id,
        zi_c_company_id,
        zi_es_location_id,
        company_name                                                    AS zi_c_name,
        company_name                                                    AS zi_c_name_display,
        zi_c_names_other,
        zi_c_url,
        zi_c_street,
        zi_c_street_2,
        city                                                            AS zi_c_city,
        "region"                                                        AS zi_c_state,
        zipcode                                                         AS zi_c_zip,
        country                                                         AS zi_c_country,
        zi_c_latitude,
        zi_c_longitude,
        zi_c_year_founded,
        zi_c_phone,
        zi_c_fax,
        zi_c_ein,
        normalized_name                                                 AS zi_eng_companyname,
        company_name                                                    AS zi_eng_dba,
        UPPER(REGEXP_REPLACE(zi_c_names_other, '[^a-zA-Z0-9 ]', ''))    AS zi_eng_dba2,
        zi_eng_website,
        street_address                                                  AS zi_eng_address,
        REGEXP_SUBSTR(street_address, '^[0-9]+')                        AS zi_eng_street_num,
        "region"                                                        AS zi_eng_state,
        city                                                            AS zi_eng_city,
        zipcode                                                         AS zi_eng_zipcode,
        SUBSTRING(zipcode, 1, 3)                                        AS zi_eng_zipcode_threedigits,
        zi_eng_zip4,
        UPPER(zi_c_county)                                              AS zi_eng_county,
        country                                                         AS zi_eng_country,
        country                                                         AS country_code,
        zi_eng_phone_number,
        zi_eng_phone_countrycode,
        zi_eng_fax_number,
        zi_eng_fax_countrycode
    FROM normalized_names AS name
        INNER JOIN normalized_addresses AS addr
                USING (
                       zi_c_location_id,
                       zi_c_company_id,
                       zi_es_location_id
            )
        INNER JOIN other_fields AS other
                USING (
                       zi_c_location_id,
                       zi_c_company_id,
                       zi_es_location_id
            );
    END
$$
